INSERT INTO public.account_search_additional_keyword (id, account_id, value)
SELECT nextval('account_search_additional_keyword_seq'), ac.id, ac.name  FROM public.account ac INNER JOIN public.account_mrtm mac ON ac.id = mac.id;

